// ====================================
// CONFIG: TikTok
// ====================================

const POST_URL = 'https://www.tiktok.com/@.white.rosee/video/7583374514919099669?is_from_webapp=1&sender_device=pc&web_id=7577351948862113298';

// 🔑 PASTE COOKIE KAMU DI SINI
// Cara ambil: Login TikTok di browser → F12 → Application → Cookies → tiktok.com
const SESSION_ID = 'fc9f6a841f5c51c01c2394ec7c8e022c';      // sessionid
const CSRF_TOKEN = '0d6715fb131e6706a4883f4c59936c0d';      // tt_csrf_token atau csrf_session_id
const MS_TOKEN  = 'pdr4YgO_AvWVOYFWkr1xw5kHYpiNYZLNkuSq53vhw773jpIj80RBTWdYWzBA74Y7eWVK16qW4FTePdJO4ybv0gf4Ykb9qI33zO8n006ZN5757TGlRt9a9a1n028d808BohN1_rFhxBzTJqA=';           // msToken (penting untuk TikTok!)

const MAX_PAGES = 50; // safety limit, 1 page ≈ 20 comments

// Extract video ID from URL
// TikTok video ID ada di URL: /video/7586250968094756097
const match = POST_URL.match(/video\/(\d+)/);
if (!match) throw new Error('Invalid TikTok URL. Expected format: https://www.tiktok.com/@user/video/VIDEO_ID');
const videoId = match[1];

const cookie = `sessionid=${SESSION_ID}; tt_csrf_token=${CSRF_TOKEN}; msToken=${MS_TOKEN};`;

// Reset static data
const staticData = $getWorkflowStaticData('global');
staticData.allComments = [];
staticData.currentPage = 0;
staticData.commentCount = 0;

console.log(`Video ID: ${videoId}`);
console.log(`URL: ${POST_URL}`);

return [{ json: {
  videoId,
  postUrl: POST_URL,
  cookie,
  csrfToken: CSRF_TOKEN,
  msToken: MS_TOKEN,
  maxPages: MAX_PAGES,
  cursor: 0,
  hasMore: true,
}}];

// ====================================
// Parse & store in staticData
// ====================================

const raw = $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.allComments) staticData.allComments = [];
staticData.currentPage = (staticData.currentPage || 0) + 1;

// Get config from previous node
let config;
try {
  config = $('Config (TikTok)').first().json;
} catch(e) {
  config = $('Loop Back').first().json;
}

// Error check
if (raw.status_code && raw.status_code !== 0) {
  console.log(`❌ TikTok error: status_code=${raw.status_code}, msg=${raw.status_msg || 'unknown'}`);
  return [{ json: {
    ...config,
    shouldContinue: false,
    error: raw.status_msg || `status_code: ${raw.status_code}`,
  }}];
}

if (typeof raw === 'string' && raw.includes('<!DOCTYPE')) {
  console.log('❌ TikTok returned HTML — session mungkin expired');
  return [{ json: { ...config, shouldContinue: false, error: 'HTML returned, cookie expired' } }];
}

// Parse comments
const comments = (raw.comments || []).map(c => ({
  id: c.cid || String(c.id || ''),
  username: c.user?.unique_id || c.user?.nickname || 'unknown',
  nickname: c.user?.nickname || '',
  avatarUrl: c.user?.avatar_thumb?.url_list?.[0] || '',
  isAuthor: c.is_author_digged || false,
  text: c.text || '',
  createdAt: c.create_time,
  createdAtISO: c.create_time ? new Date(c.create_time * 1000).toISOString() : null,
  likeCount: c.digg_count || 0,
  replyCount: c.reply_comment_total || 0,
  isPinned: c.is_pinned || false,
}));

// Accumulate in staticData
staticData.allComments.push(...comments);
staticData.commentCount = raw.total_comments || staticData.allComments.length;

// Pagination
const hasMore = raw.has_more === 1 || raw.has_more === true;
const nextCursor = raw.cursor || 0;
const shouldContinue = hasMore && comments.length > 0 && staticData.currentPage < (config.maxPages || 50);

console.log(`📄 Page ${staticData.currentPage}: +${comments.length} comments (total: ${staticData.allComments.length}/${staticData.commentCount}) | hasMore: ${hasMore} | cursor: ${nextCursor}`);

return [{ json: {
  videoId: config.videoId,
  postUrl: config.postUrl,
  cookie: config.cookie,
  csrfToken: config.csrfToken,
  msToken: config.msToken,
  maxPages: config.maxPages,
  cursor: nextCursor,
  shouldContinue,
}}];

// ====================================
// Loop Back
// ====================================
const input = $input.first().json;
console.log(`🔄 Looping to next page... (cursor: ${input.cursor})`);
return [{ json: input }];

// ====================================
// FINAL: Ambil SEMUA comments dari staticData
// ====================================

const staticData = $getWorkflowStaticData('global');
const allComments = staticData.allComments || [];
const commentCount = staticData.commentCount || 0;
const pagesScraped = staticData.currentPage || 0;

const input = $input.first().json;

console.log(`✅ FINAL: ${allComments.length} total comments from ${pagesScraped} pages`);

// Clean up static data
staticData.allComments = [];
staticData.currentPage = 0;
staticData.commentCount = 0;

if (allComments.length === 0) {
  return [{ json: {
    status: 'empty',
    message: 'Tidak ada komentar yang berhasil di-scrape.',
    videoId: input.videoId,
    pagesScraped,
    tip: 'Pastikan cookie (sessionid, msToken) valid. TikTok lebih strict dari IG.',
  }}];
}

return [{ json: {
  postUrl: input.postUrl,
  videoId: input.videoId,
  totalCommentCount: commentCount,
  totalCollected: allComments.length,
  pagesScraped,
  scrapedAt: new Date().toISOString(),
  comments: allComments,
}}];

// ====================================
// Output: 1 row per comment
// ====================================

const data = $input.first().json;
const comments = data.comments || [];

if (comments.length === 0) {
  return [{ json: {
    status: 'empty',
    message: `Tidak ada komentar dari ${data.postUrl}`,
  }}];
}

console.log(`📊 Exporting ${comments.length} comments as rows`);

return comments.map((c, i) => ({
  json: {
    no: i + 1,
    post_url: data.postUrl,
    video_id: data.videoId,
    username: c.username,
    nickname: c.nickname,
    comment_text: c.text,
    likes: c.likeCount,
    reply_count: c.replyCount,
    is_pinned: c.isPinned,
    posted_at: c.createdAtISO,
    scraped_at: data.scrapedAt,
  }
}));
